module xor_8bit_en (
    input_data,
    A,
    B,
    EN
);

    output reg [7:0] input_data;
    input [7:0] A;
    input [7:0] B;
    input EN;

    always @(*) begin
        if (EN) begin
            input_data = A ^ B;
        end
        else begin
            input_data = 8'b0;
        end
    end

endmodule
